#[cfg(test)]
mod tests {
    use alloy_primitives::{Address, Bytes};
    use revm_context::{AsyncCommitmentutionContext, ExecutionMode};

let context = AsyncCommitmentutionContext::default();

assert_eq!(context.execution_mode, ExecutionMode::Building);
assert_eq!(context.spc_call_index, 0);
assert!(context.execution_results.is_empty());

let mut context = AsyncCommitmentutionContext::default();
assert_eq!(context.execution_mode, ExecutionMode::Building);
context.execution_mode = ExecutionMode::Verification;
assert_eq!(context.execution_mode, ExecutionMode::Verification);
context.execution_mode = ExecutionMode::Building;
assert_eq!(context.execution_mode, ExecutionMode::Building);

let mut context = AsyncCommitmentutionContext::default();
let address = Address::ZERO;
let result = Bytes::from(vec![0x42, 0x43, 0x44]);
context.execution_results.insert(address, result.clone());
assert!(!context.execution_results.is_empty());
assert_eq!(context.execution_results.get(&address).unwrap(), &result);

let mut context = AsyncCommitmentutionContext::default();
assert_eq!(context.spc_call_index, 0);
context.increment_spc_call_index();
assert_eq!(context.spc_call_index, 1);
context.increment_spc_call_index();
assert_eq!(context.spc_call_index, 2);

assert!(context.pending_spc_calls.is_empty());
let spc_call = SpcCall::new(
    Address::ZERO,
    Bytes::from(vec![0x01, 0x02]),
    Bytes::from(vec![0x03, 0x04]),
    Bytes::from(vec![0x05, 0x06]),
    42u64,
    Some(100),
    Address::with_last_byte(0x42),
);
context.pending_spc_calls.push(spc_call.clone());
assert_eq!(context.pending_spc_calls.len(), 1);
assert_eq!(context.pending_spc_calls[0], spc_call);

let spc_call = SpcCall::new(
    Address::ZERO,
    Bytes::from(vec![0x01, 0x02]),
    Bytes::from(vec![0x03, 0x04]),
    Bytes::from(vec![0x05, 0x06]),
    42u64,
    Some(100),                     // program_counter
    Address::with_last_byte(0x42), // caller_address
);
